const SANITY_CONFIG={projectId:"8t5h923j",dataset:"production",apiVersion:"2025-02-05",useCdn:!1,perspective:"published"};async function fetchArtistsFromSanity(t=null,n=!1){try{let e=n?'*[_type == "artist" && featured == true]':'*[_type == "artist"]';e+=" | order(_createdAt desc)",t&&(e+=`[0...${t}]`),e+='{\n      _id,\n      name,\n      "slug": slug.current,\n      shortDescription,\n      subtitle,\n      image{\n        asset->{_id, url, metadata{lqip, dimensions}},\n        alt\n      },\n      gallery[]{\n        asset->{_id, url, metadata{lqip, dimensions}},\n        alt,\n        _key\n      },\n      bio,\n      style,\n      status,\n      featured,\n      whatsapp,\n      country,\n      seoTitle,\n      seoDescription\n    }';const r=`https://${SANITY_CONFIG.projectId}.api.sanity.io/v${SANITY_CONFIG.apiVersion}/data/query/${SANITY_CONFIG.dataset}?query=${encodeURIComponent(e)}`,s=await fetch(r,{cache:"no-store"});return(await s.json()).result||[]}catch(t){return console.error("❌ fetchArtistsFromSanity error:",t),[]}}async function fetchArtistBySlug(t){try{const n=`*[\n      _type == "artist" &&\n      (slug.current == "${t}" || _id == "${t}")\n    ][0]{\n      _id,\n      name,\n      "slug": slug.current,\n      shortDescription,\n      subtitle,\n      image{\n        asset->{_id, url, metadata{lqip, dimensions}},\n        alt\n      },\n      gallery[]{\n        asset->{_id, url, metadata{lqip, dimensions}},\n        alt,\n        _key\n      },\n      bio,\n      style,\n      status,\n      featured,\n      whatsapp,\n      country,\n      seoTitle,\n      seoDescription\n    }`,e=`https://${SANITY_CONFIG.projectId}.api.sanity.io/v${SANITY_CONFIG.apiVersion}/data/query/${SANITY_CONFIG.dataset}?query=${encodeURIComponent(n)}`,r=await fetch(e,{cache:"no-store"});return(await r.json()).result||null}catch(t){return console.error("❌ fetchArtistBySlug error:",t),null}}async function fetchFeaturedArtworks(t=null){try{let n='\n      *[\n        _type == "artwork" &&\n        featured == true &&\n        (!defined(status) || status in ["published", "sold"])\n      ]\n      | order(coalesce(order, 999) asc, _createdAt desc)\n    ';t&&(n+=`[0...${t}]`),n+='{\n      _id,\n      title,\n      order,\n      "slug": slug.current,\n      shortDescription,\n      image{\n        asset->{_id, url, metadata{lqip, dimensions}},\n        alt\n      },\n      images[]{\n        asset->{_id, url, metadata{lqip, dimensions}},\n        alt,\n        _key\n      },\n      year,\n      medium,\n      dimensions,\n      category,\n      description,\n      price,\n      status,\n      featured,\n      "artist": artist->{\n        _id,\n        name,\n        "slug": slug.current\n      }\n    }';const e=`https://${SANITY_CONFIG.projectId}.api.sanity.io/v${SANITY_CONFIG.apiVersion}/data/query/${SANITY_CONFIG.dataset}?query=${encodeURIComponent(n)}`,r=await fetch(e,{cache:"no-store"});return(await r.json()).result||[]}catch(t){return console.error("❌ fetchFeaturedArtworks error:",t),[]}}window.fetchArtistsFromSanity=fetchArtistsFromSanity,window.fetchArtistBySlug=fetchArtistBySlug,window.fetchFeaturedArtworks=fetchFeaturedArtworks;